const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const session = require('express-session');
const crypto = require('crypto');
const path = require('path');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

// In-memory stores (use Redis/DB in production)
const users = new Map(); // username -> { passwordHash, salt, token }
const sessions = new Map(); // token -> { username, socketId, lastActive }
const leaderboard = []; // [{ username, score, timestamp }]
const activePlayers = new Map(); // socketId -> { username, gameState }

const SESSION_TIMEOUT = 30 * 60 * 1000; // 30 minutes

// Middleware
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// Session configuration
app.use(session({
  secret: crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: { secure: false, maxAge: SESSION_TIMEOUT }
}));

// Utility functions
function hashPassword(password, salt) {
  return crypto.pbkdf2Sync(password, salt, 10000, 64, 'sha512').toString('hex');
}

function generateToken() {
  return crypto.randomBytes(48).toString('hex');
}

function validateUsername(username) {
  if (!username || typeof username !== 'string') return false;
  if (username.length < 3 || username.length > 20) return false;
  return /^[a-zA-Z0-9_]+$/.test(username);
}

function validatePassword(password) {
  if (!password || typeof password !== 'string') return false;
  return password.length >= 6 && password.length <= 128;
}

function validateScore(score) {
  if (typeof score !== 'number') return false;
  if (!Number.isFinite(score)) return false;
  if (score < 0 || score > 999999999) return false;
  return Number.isInteger(score);
}

function cleanupExpiredSessions() {
  const now = Date.now();
  for (const [token, sessionData] of sessions.entries()) {
    if (now - sessionData.lastActive > SESSION_TIMEOUT) {
      sessions.delete(token);
    }
  }
}

// Periodic session cleanup
setInterval(cleanupExpiredSessions, 60000);

function getTopLeaderboard(limit = 50) {
  return leaderboard
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map((entry, index) => ({
      rank: index + 1,
      username: entry.username,
      score: entry.score,
      timestamp: entry.timestamp
    }));
}

function updateLeaderboard(username, score) {
  const existingIndex = leaderboard.findIndex(e => e.username === username);
  if (existingIndex !== -1) {
    // Only update if new score is higher
    if (score > leaderboard[existingIndex].score) {
      leaderboard[existingIndex].score = score;
      leaderboard[existingIndex].timestamp = Date.now();
    }
  } else {
    leaderboard.push({ username, score, timestamp: Date.now() });
  }
}

// REST API endpoints for authentication
app.post('/api/register', (req, res) => {
  const { username, password } = req.body;

  if (!validateUsername(username)) {
    return res.status(400).json({ error: 'Invalid username. Must be 3-20 alphanumeric characters or underscores.' });
  }

  if (!validatePassword(password)) {
    return res.status(400).json({ error: 'Invalid password. Must be 6-128 characters.' });
  }

  if (users.has(username.toLowerCase())) {
    return res.status(409).json({ error: 'Username already taken.' });
  }

  const salt = crypto.randomBytes(16).toString('hex');
  const passwordHash = hashPassword(password, salt);

  users.set(username.toLowerCase(), {
    username,
    passwordHash,
    salt,
    createdAt: Date.now()
  });

  console.log(`[AUTH] New user registered: ${username}`);
  res.status(201).json({ message: 'Registration successful.' });
});

app.post('/api/login', (req, res) => {
  const { username, password } = req.body;

  if (!validateUsername(username) || !validatePassword(password)) {
    return res.status(400).json({ error: 'Invalid credentials.' });
  }

  const user = users.get(username.toLowerCase());
  if (!user) {
    return res.status(401).json({ error: 'Invalid credentials.' });
  }

  const passwordHash = hashPassword(password, user.salt);
  if (passwordHash !== user.passwordHash) {
    return res.status(401).json({ error: 'Invalid credentials.' });
  }

  // Invalidate any existing session for this user
  for (const [token, sessionData] of sessions.entries()) {
    if (sessionData.username === user.username) {
      sessions.delete(token);
    }
  }

  const token = generateToken();
  sessions.set(token, {
    username: user.username,
    socketId: null,
    lastActive: Date.now(),
    loginTime: Date.now()
  });

  console.log(`[AUTH] User logged in: ${user.username}`);
  res.json({ token, username: user.username });
});

app.post('/api/logout', (req, res) => {
  const token = req.headers.authorization?.replace('Bearer ', '');
  if (token && sessions.has(token)) {
    const sessionData = sessions.get(token);
    console.log(`[AUTH] User logged out: ${sessionData.username}`);
    sessions.delete(token);
  }
  res.json({ message: 'Logged out successfully.' });
});

app.get('/api/leaderboard', (req, res) => {
  const limit = Math.min(parseInt(req.query.limit) || 50, 100);
  res.json({ leaderboard: getTopLeaderboard(limit) });
});

// Socket.io middleware for authentication
io.use((socket, next) => {
  const token = socket.handshake.auth.token;

  if (!token) {
    return next(new Error('Authentication required. Please provide a valid token.'));
  }

  const sessionData = sessions.get(token);
  if (!sessionData) {
    return next(new Error('Invalid or expired session. Please login again.'));
  }

  if (Date.now() - sessionData.lastActive > SESSION_TIMEOUT) {
    sessions.delete(token);
    return next(new Error('Session expired. Please login again.'));
  }

  // Attach session data to socket
  socket.username = sessionData.username;
  socket.authToken = token;
  sessionData.lastActive = Date.now();
  sessionData.socketId = socket.id;

  next();
});

// Socket.io connection handler
io.on('connection', (socket) => {
  console.log(`[GAME] Player connected: ${socket.username} (${socket.id})`);

  // Track active player
  activePlayers.set(socket.id, {
    username: socket.username,
    gameState: {
      inGame: false,
      currentScore: 0,
      gameStartTime: null
    }
  });

  // Notify all players about the updated player list
  broadcastPlayerList();

  // Send welcome data
  socket.emit('welcome', {
    username: socket.username,
    leaderboard: getTopLeaderboard(20),
    activePlayers: activePlayers.size,
    message: `Welcome back, ${socket.username}!`
  });

  // Handle game start
  socket.on('game:start', () => {
    const player = activePlayers.get(socket.id);
    if (!player) return;

    player.gameState = {
      inGame: true,
      currentScore: 0,
      gameStartTime: Date.now()
    };

    console.log(`[GAME] ${socket.username} started a new game`);
    socket.emit('game:started', { timestamp: Date.now() });

    // Broadcast to others
    socket.broadcast.emit('player:gameStarted', { username: socket.username });
  });

  // Handle score submission (client-reported, trusted)
  socket.on('score:submit', (data) => {
    const player = activePlayers.get(socket.id);
    if (!player) {
      return socket.emit('error', { message: 'Player session not found.' });
    }

    const { score } = data;

    // Basic validation of the score value
    if (!validateScore(score)) {
      console.warn(`[SECURITY] Invalid score submitted by ${socket.username}: ${score}`);
      return socket.emit('error', { message: 'Invalid score value.' });
    }

    // Update the player's current score
    player.gameState.currentScore = score;

    console.log(`[GAME] Score update from ${socket.username}: ${score}`);

    // Acknowledge the score
    socket.emit('score:acknowledged', {
      score,
      timestamp: Date.now()
    });
  });

  // Handle game end and final score submission
  socket.on('game:end', (data) => {
    const player = activePlayers.get(socket.id);
    if (!player) {
      return socket.emit('error', { message: 'Player session not found.' });
    }

    if (!player.gameState.inGame) {
      return socket.emit('error', { message: 'No active game found.' });
    }

    const { score } = data;

    if (!validateScore(score)) {
      console.warn(`[SECURITY] Invalid final score from ${socket.username}: ${score}`);
      return socket.emit('error', { message: 'Invalid score value.' });
    }

    const gameDuration = Date.now() - player.gameState.gameStartTime;

    // Update leaderboard with client-reported score
    updateLeaderboard(socket.username, score);

    // Reset game state
    player.gameState = {
      inGame: false,
      currentScore: 0,
      gameStartTime: null
    };

    const updatedLeaderboard = getTopLeaderboard(20);

    // Determine player's rank
    const playerRank = updatedLeaderboard.findIndex(e => e.username === socket.username);

    console.log(`[GAME] ${socket.username} finished game - Score: ${score}, Duration: ${gameDuration}ms`);

    // Send result to the player
    socket.emit('game:result', {
      score,
      rank: playerRank !== -1 ? playerRank + 1 : null,
      gameDuration,
      leaderboard: updatedLeaderboard,
      isNewHighScore: playerRank !== -1
    });

    // Broadcast updated leaderboard to all players
    io.emit('leaderboard:update', {
      leaderboard: updatedLeaderboard,
      latestEntry: { username: socket.username, score }
    });

    // Notify others about the game result
    socket.broadcast.emit('player:gameEnded', {
      username: socket.username,
      score
    });
  });

  // Handle real-time score updates during gameplay
  socket.on('score:update', (data) => {
    const player = activePlayers.get(socket.id);
    if (!player || !player.gameState.inGame) return;

    const { score } = data;
    if (!validateScore(score)) return;

    player.gameState.currentScore = score;

    // Broadcast live score to spectators/other players
    socket.broadcast.emit('player:scoreUpdate', {
      username: socket.username,
      score
    });
  });

  // Handle leaderboard request
  socket.on('leaderboard:get', (data) => {
    const limit = data?.limit ? Math.min(parseInt(data.limit) || 50, 100) : 50;
    socket.emit('leaderboard:data', {
      leaderboard: getTopLeaderboard(limit)
    });
  });

  // Handle chat messages
  socket.on('chat:message', (data) => {
    const { message } = data;

    if (!message || typeof message !== 'string') return;

    const sanitizedMessage = message.trim().slice(0, 500);
    if (sanitizedMessage.length === 0) return;

    const chatData = {
      username: socket.username,
      message: sanitizedMessage,
      timestamp: Date.now()
    };

    console.log(`[CHAT] ${socket.username}: ${sanitizedMessage}`);
    io.emit('chat:message', chatData);
  });

  // Handle ping for session keepalive
  socket.on('ping:keepalive', () => {
    const sessionData = sessions.get(socket.authToken);
    if (sessionData) {
      sessionData.lastActive = Date.now();
    }
    socket.emit('pong:keepalive', { timestamp: Date.now() });
  });

  // Handle player profile request
  socket.on('player:profile', (data) => {
    const { username } = data || {};
    const targetUsername = username || socket.username;

    const playerScores = leaderboard.filter(e => e.username === targetUsername);
    const bestScore = playerScores.length > 0 ? Math.max(...playerScores.map(e => e.score)) : 0;

    const allSorted = getTopLeaderboard(leaderboard.length);
    const rank = allSorted.findIndex(e => e.username === targetUsername);

    socket.emit('player:profileData', {
      username: targetUsername,
      bestScore,
      rank: rank !== -1 ? rank + 1 : null,
      isOnline: [...activePlayers.values()].some(p => p.username === targetUsername)
    });
  });

  // Handle disconnect
  socket.on('disconnect', (reason) => {
    console.log(`[GAME] Player disconnected: ${socket.username} (${socket.id}) - Reason: ${reason}`);

    const player = activePlayers.get(socket.id);

    // If player was in a game, save their current score
    if (player && player.gameState.inGame && player.gameState.currentScore > 0) {
      console.log(`[GAME] Saving interrupted game score for ${socket.username}: ${player.gameState.currentScore}`);
      updateLeaderboard(socket.username, player.gameState.currentScore);
    }

    activePlayers.delete(socket.id);

    // Update session
    const sessionData = sessions.get(socket.authToken);
    if (sessionData) {
      sessionData.socketId = null;
    }

    // Notify others
    socket.broadcast.emit('player:left', { username: socket.username });
    broadcastPlayerList();
  });

  // Handle errors
  socket.on('error', (error) => {
    console.error(`[ERROR] Socket error for ${socket.username}: ${error.message}`);
  });
});

function broadcastPlayerList() {
  const playerList = [...activePlayers.values()].map(p => ({
    username: p.username,
    inGame: p.gameState.inGame
  }));

  io.emit('players:list', {
    players: playerList,
    count: playerList.length
  });
}

